#include <iostream>
#include <cmath>
using namespace std;

int countDigits(int n) {
    int count = 0;
    while (n > 0) {
        count++;
        n /= 10;
    }
    return count;
}

// Function to check if a num is Armstrong: print YES or NO
void isArmstrongNumber(int num) {
    int n = num, sum = 0;
    int digits = countDigits(num);
    while (n > 0) {
        int d = n % 10;
        sum += std::pow(d, digits);
        n /= 10;
    }
    if (sum == num)
        cout << "YES";
    else
        cout << "NO";
}

int main() {
    int n;
    std::cin >> n;

    isArmstrongNumber(n);
    return 0;
}

